3	namespace App\Services;
4	
5	use App\Models\Appointment;
6	use App\Models\User;
7	use App\Repositories\AppointmentRepository;
8	use App\Repositories\AppointmentVersionRepository;
9	use App\Support\AuditLogger;
10	use Carbon\Carbon;
11	use Carbon\CarbonInterface;
12	
13	class AppointmentService
14	{
15	    private const TRANSITIONS = [
16	        Appointment::STATUS_REQUESTED => [Appointment::STATUS_CONFIRMED],
17	        Appointment::STATUS_CONFIRMED => [Appointment::STATUS_CHECKED_IN, Appointment::STATUS_NO_SHOW, Appointment::STATUS_CANCELLED],
18	        Appointment::STATUS_CHECKED_IN => [Appointment::STATUS_COMPLETED, Appointment::STATUS_CANCELLED],
19	        Appointment::STATUS_NO_SHOW => [],
20	        Appointment::STATUS_COMPLETED => [],
21	        Appointment::STATUS_CANCELLED => [],
22	    ];
23	
24	    public function __construct(
25	        private readonly AppointmentRepository $appointmentRepository,
26	        private readonly AppointmentVersionRepository $appointmentVersionRepository,
27	        private readonly FeeService $feeService,
28	    ) {
29	    }
30	
31	    public function createAppointment(array $data, User $actor): array
32	    {
33	        $start = Carbon::parse($data['start_time']);
34	        $end = Carbon::parse($data['end_time']);
35	
36	        if (! $start->lt($end)) {
37	            return [
38	                'success' => false,
39	                'error' => 'INVALID_TIME_RANGE',
40	                'data' => [],
41	                'status' => 422,
42	            ];
43	        }
44	
45	        $siteId = (int) ($data['site_id'] ?? $actor->site_id ?? 0);
46	        $providerId = (int) $data['provider_id'];
47	        $resourceId = (int) $data['resource_id'];
48	
49	        $conflicts = $this->appointmentRepository->overlappingConflicts(
50	            $providerId,
51	            $resourceId,
52	            $start,
53	            $end,
54	            $siteId,
55	        );
56	
57	        if ($conflicts->isNotEmpty()) {
58	            $conflict = $conflicts->first();
59	            $conflictType = $conflict->provider_id === $providerId ? 'provider' : 'resource';
60	
61	            return [
62	                'success' => false,
63	                'error' => 'APPOINTMENT_CONFLICT',
64	                'data' => [
65	                    'conflict_type' => $conflictType,
66	                    'next_available_slots' => $this->getNextAvailableSlots($providerId, $resourceId, $end, 3, $siteId),
67	                ],
68	                'status' => 409,
69	            ];
70	        }
71	
72	        $appointment = $this->appointmentRepository->create([
73	            'client_id' => (int) $data['client_id'],
74	            'provider_id' => $providerId,
75	            'resource_id' => $resourceId,
76	            'service_type' => $data['service_type'],
77	            'start_time' => $start,
78	            'end_time' => $end,
79	            'status' => Appointment::STATUS_REQUESTED,
80	            'site_id' => $siteId,
81	            'department_id' => (int) $data['department_id'],
82	        ]);
83	
84	        $this->appointmentVersionRepository->createSnapshot($appointment, $actor->id);
85	
86	        AuditLogger::write(
87	            $actor->id,
88	            'CREATE_APPOINTMENT',
89	            Appointment::class,
90	            $appointment->id,
91	            [
92	                'status' => $appointment->status,
93	                'start_time' => $appointment->start_time->toIso8601String(),
94	                'end_time' => $appointment->end_time->toIso8601String(),
95	            ],
96	            request()->ip(),
97	        );
98	
99	        return [
100	            'success' => true,
101	            'data' => [
102	                'appointment' => $appointment->fresh(['client', 'provider', 'resource']),
103	            ],
104	            'status' => 201,
105	        ];
106	    }
107	
108	    public function rescheduleAppointment(Appointment $appointment, array $data, User $actor, ?string $reason = null): array
109	    {
110	        $start = Carbon::parse($data['start_time']);
111	        $end = Carbon::parse($data['end_time']);
112	
113	        if (! $start->lt($end)) {
114	            return [
115	                'success' => false,
116	                'error' => 'INVALID_TIME_RANGE',
117	                'data' => [],
118	                'status' => 422,
119	            ];
120	        }
121	
122	        $providerId = (int) ($data['provider_id'] ?? $appointment->provider_id);
123	        $resourceId = (int) ($data['resource_id'] ?? $appointment->resource_id);
124	        $siteId = (int) $appointment->site_id;
125	
126	        $conflicts = $this->appointmentRepository->overlappingConflicts(
127	            $providerId,
128	            $resourceId,
129	            $start,
130	            $end,
131	            $siteId,
132	            $appointment->id,
133	        );
134	
135	        if ($conflicts->isNotEmpty()) {
136	            $conflict = $conflicts->first();
137	            $conflictType = $conflict->provider_id === $providerId ? 'provider' : 'resource';
138	
139	            return [
140	                'success' => false,
141	                'error' => 'APPOINTMENT_CONFLICT',
142	                'data' => [
143	                    'conflict_type' => $conflictType,
144	                    'next_available_slots' => $this->getNextAvailableSlots($providerId, $resourceId, $end, 3, $siteId),
145	                ],
146	                'status' => 409,
147	            ];
148	        }
149	
150	        $appointment->fill([
151	            'start_time' => $start,
152	            'end_time' => $end,
153	            'provider_id' => $providerId,
154	            'resource_id' => $resourceId,
155	            'reschedule_reason' => $reason,
156	        ]);
157	
158	        $this->appointmentRepository->save($appointment);
159	        $this->appointmentVersionRepository->createSnapshot($appointment, $actor->id);
160	
161	        AuditLogger::write(
162	            $actor->id,
163	            'RESCHEDULE_APPOINTMENT',
164	            Appointment::class,
165	            $appointment->id,
166	            [
167	                'start_time' => $appointment->start_time->toIso8601String(),
168	                'end_time' => $appointment->end_time->toIso8601String(),
169	                'reschedule_reason' => $reason,
170	            ],
171	            request()->ip(),
172	        );
173	
174	        return [
175	            'success' => true,
176	            'data' => [
177	                'appointment' => $appointment->fresh(['client', 'provider', 'resource']),
178	            ],
179	            'status' => 200,
180	        ];
181	    }
182	
183	    public function transitionStatus(Appointment $appointment, string $newStatus, User $actor, ?string $reason = null): array
184	    {
185	        $current = $appointment->status;
186	        $allowed = self::TRANSITIONS[$current] ?? [];
187	
188	        if (! in_array($newStatus, $allowed, true)) {
189	            return [
190	                'success' => false,
191	                'error' => 'INVALID_TRANSITION',
192	                'data' => [
193	                    'from' => $current,
194	                    'to' => $newStatus,
195	                ],
196	                'status' => 422,
197	            ];
198	        }
199	
200	        if (! $this->canTransition($actor, $newStatus)) {
201	            return [
202	                'success' => false,
203	                'error' => 'FORBIDDEN',
204	                'data' => [],
205	                'status' => 403,
206	            ];
207	        }
208	
209	        if ($newStatus === Appointment::STATUS_CANCELLED && ! $reason) {
210	            return [
211	                'success' => false,
212	                'error' => 'VALIDATION_ERROR',
213	                'data' => ['cancel_reason' => ['The cancel_reason field is required when cancelling.']],
214	                'status' => 422,
215	            ];
216	        }
217	
218	        $appointment->status = $newStatus;
219	        $appointment->cancel_reason = $newStatus === Appointment::STATUS_CANCELLED ? $reason : null;
220	
221	        if ($newStatus === Appointment::STATUS_NO_SHOW) {
222	            $appointment->assessed_no_show = true;
223	        }
224	
225	        $this->appointmentRepository->save($appointment);
226	
227	        $this->appointmentVersionRepository->createSnapshot($appointment, $actor->id);
228	
229	        if ($newStatus === Appointment::STATUS_NO_SHOW && $this->feeService->isGracePeriodElapsed($appointment)) {
230	            $this->feeService->assessNoShowFee($appointment);
231	        }
232	
233	        if ($newStatus === Appointment::STATUS_CANCELLED) {
234	            app(WaitlistService::class)->proposeBackfill($appointment, $actor);
235	        }
236	
237	        AuditLogger::write(
238	            $actor->id,
239	            'TRANSITION_APPOINTMENT',
240	            Appointment::class,
241	            $appointment->id,
242	            [
243	                'from' => $current,
244	                'to' => $newStatus,
245	                'reason' => $reason,
246	            ],
247	            request()->ip(),
248	        );
249	
250	        return [
251	            'success' => true,
252	            'data' => [
253	                'appointment' => $appointment->fresh(['client', 'provider', 'resource']),
254	            ],
255	            'status' => 200,
256	        ];
257	    }
258	
259	    public function getNextAvailableSlots(
260	        int $providerId,
261	        int $resourceId,
262	        CarbonInterface|string $after,
263	        int $count = 3,
264	        ?int $siteId = null,
265	    ): array {
266	        $cursor = $after instanceof CarbonInterface ? $after->copy() : Carbon::parse($after);
267	        $cursor = $cursor->second(0);
268	
269	        $slots = [];
270	        $attempts = 0;
271	
272	        while (count($slots) < $count && $attempts < 96) {
273	            $slotStart = $cursor->copy();
274	            $slotEnd = $slotStart->copy()->addMinutes(30);
275	
276	            $isBlocked = $this->appointmentRepository->confirmedOrCheckedInForWindow(
277	                $providerId,
278	                $resourceId,
279	                $slotStart,
280	                $slotEnd,
281	                $siteId,
282	            );
283	
284	            if (! $isBlocked) {
285	                $slots[] = [
286	                    'start_time' => $slotStart->toIso8601String(),
287	                    'end_time' => $slotEnd->toIso8601String(),
288	                ];
289	            }
290	
291	            $cursor = $cursor->addMinutes(30);
292	            $attempts++;
293	        }
294	
295	        return $slots;
296	    }
297	
298	    private function canTransition(User $actor, string $newStatus): bool
299	    {
300	        if ($actor->role === 'administrator') {
301	            return true;
302	        }
303	
304	        if ($actor->role !== 'staff') {
305	            return false;
306	        }
307	
308	        return in_array($newStatus, [
309	            Appointment::STATUS_CONFIRMED,
310	            Appointment::STATUS_CHECKED_IN,
311	            Appointment::STATUS_NO_SHOW,
312	            Appointment::STATUS_COMPLETED,
313	            Appointment::STATUS_CANCELLED,
314	        ], true);
315	    }
316	}
