14	class AdminUserController extends Controller
15	{
16	    public function resetPassword(Request $request, User $user): JsonResponse
17	    {
18	        $actor = $request->user();
19	
20	        if ($actor->role !== 'administrator') {
21	            return response()->json([
22	                'success' => false,
23	                'error' => 'FORBIDDEN',
24	                'data' => [],
25	            ], Response::HTTP_FORBIDDEN);
26	        }
27	
28	        $validated = $request->validate([
