1	<?php
2	
3	namespace App\Services;
4	
5	use App\Models\Appointment;
6	use App\Models\User;
7	use App\Models\WaitlistEntry;
8	use App\Repositories\WaitlistRepository;
9	use App\Support\AuditLogger;
10	use Illuminate\Pagination\LengthAwarePaginator;
11	
12	class WaitlistService
13	{
14	    public function __construct(
15	        private readonly WaitlistRepository $waitlistRepository,
16	        private readonly AppointmentService $appointmentService,
17	    ) {
18	    }
19	
20	    public function listForSite(?int $siteId, ?int $departmentId = null, int $perPage = 20, int $page = 1): LengthAwarePaginator
21	    {
22	        return $this->waitlistRepository->listBySite($siteId, $departmentId, $perPage, $page);
23	    }
24	
25	    public function addToWaitlist(array $data, User $actor): WaitlistEntry
26	    {
27	        $entry = $this->waitlistRepository->create([
28	            'client_id' => (int) $data['client_id'],
29	            'service_type' => $data['service_type'],
30	            'priority' => (int) $data['priority'],
31	            'preferred_start' => $data['preferred_start'],
32	            'preferred_end' => $data['preferred_end'],
33	            'status' => 'waiting',
34	            'site_id' => (int) $data['site_id'],
35	            'department_id' => isset($data['department_id']) ? (int) $data['department_id'] : null,
36	        ]);
37	
38	        AuditLogger::write(
39	            $actor->id,
40	            'WAITLIST_ADD',
41	            WaitlistEntry::class,
42	            $entry->id,
43	            ['priority' => $entry->priority, 'service_type' => $entry->service_type],
44	            request()->ip(),
45	        );
46	
47	        return $entry;
48	    }
49	
50	    public function proposeBackfill(Appointment $cancelledAppt, User $actor): ?WaitlistEntry
51	    {
52	        $entry = $this->waitlistRepository->topMatchingForBackfill(
53	            $cancelledAppt,
54	            $cancelledAppt->start_time,
55	            $cancelledAppt->end_time,
56	        );
57	
58	        if (! $entry) {
59	            return null;
60	        }
61	
62	        $entry->status = 'proposed';
63	        $this->waitlistRepository->save($entry);
64	
65	        AuditLogger::write(
66	            $actor->id,
67	            'BACKFILL_PROPOSED',
68	            WaitlistEntry::class,
69	            $entry->id,
70	            [
71	                'appointment_id' => $cancelledAppt->id,
72	                'service_type' => $entry->service_type,
73	            ],
74	            request()->ip(),
75	        );
76	
77	        return $entry;
78	    }
79	
80	    public function confirmBackfill(int $waitlistId, array $slotData, User $actor): array
81	    {
82	        $entry = $this->waitlistRepository->findById($waitlistId);
83	
84	        if (! $entry || $entry->status !== 'proposed') {
85	            return [
86	                'success' => false,
87	                'error' => 'WAITLIST_NOT_PROPOSED',
88	                'data' => [],
89	                'status' => 422,
90	            ];
91	        }
92	
93	        if ($actor->role === 'staff' && $entry->department_id !== null && (int) $entry->department_id !== (int) $actor->department_id) {
94	            return [
95	                'success' => false,
96	                'error' => 'FORBIDDEN',
97	                'data' => [],
98	                'status' => 403,
99	            ];
100	        }
101	
102	        $result = $this->appointmentService->createAppointment([
103	            'client_id' => $entry->client_id,
104	            'provider_id' => (int) $slotData['provider_id'],
105	            'resource_id' => (int) $slotData['resource_id'],
106	            'service_type' => $entry->service_type,
107	            'start_time' => $slotData['start_time'],
108	            'end_time' => $slotData['end_time'],
109	            'department_id' => (int) $slotData['department_id'],
110	            'site_id' => $entry->site_id,
111	        ], $actor);
112	
113	        if (! ($result['success'] ?? false)) {
114	            return $result;
115	        }
116	
117	        $entry->status = 'booked';
118	        $this->waitlistRepository->save($entry);
119	
120	        AuditLogger::write(
121	            $actor->id,
122	            'BACKFILL_CONFIRMED',
123	            WaitlistEntry::class,
124	            $entry->id,
125	            ['appointment_id' => $result['data']['appointment']['id'] ?? null],
126	            request()->ip(),
127	        );
128	
129	        return [
130	            'success' => true,
131	            'data' => [
132	                'waitlist' => $entry,
